// Extract raw text from OpenRouter v1 response
const raw = $json.output[0].content[0].text;

// Remove markdown wrapping if present
const cleaned = raw.replace(/```json|```/g, '').trim();

// Convert string to actual JSON object
const parsed = JSON.parse(cleaned);

// Return parsed JSON so next nodes can access fields directly
return [
  {
    json: parsed
  }
];

const raw = $json.output?.[0]?.content?.[0]?.text;
