const company = $node["Get dataset items"].json.company;

if (!raw) {
  return [{
    json: {
      error: "No model output found. Check that this Code node is connected directly after the Cover Letter HTTP Request node.",
      availableKeys: Object.keys($json),
      sample: $json,
    }
  }];
}

return [{
  json: {
    job_title: title,
    company,
    cover_letter: (raw || "").replace(/```/g, "").trim()
  }
}];
